/**
 * Regenerates fixtures.json — snapshot fixtures proving the Rust filter
 * matches the Node.js implementations byte-for-byte.
 *
 * Content/secret/truncation/tool cases run through the production hook
 * filter (plugins/kindling-claude-code/hooks/lib/filter.js); excluded-path
 * cases run through the adapter filter (packages/kindling-adapter-claude-code,
 * built dist — run `pnpm run build` first).
 *
 * Usage (from the repo root):
 *   node crates/kindling-filter/tests/fixtures/generate-fixtures.mjs
 */

import { writeFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const here = dirname(fileURLToPath(import.meta.url));
const repoRoot = join(here, '..', '..', '..', '..');

const hookFilter = await import(
  join(repoRoot, 'plugins', 'kindling-claude-code', 'hooks', 'lib', 'filter.js')
);
const adapterFilter = await import(
  join(repoRoot, 'packages', 'kindling-adapter-claude-code', 'dist', 'index.js')
);

const CONTENT_CASES = [
  ['plain text untouched', 'just some ordinary log output, nothing to see'],
  ['empty string', ''],
  ['api key assignment', 'api_key=abcdef123456789 and more text'],
  ['api key with colon and quotes', 'config: { "apiKey": "sk_live_abcdef12345678" }'],
  ['password colon', 'password: hunter2hunter2'],
  ['password too short to mask', 'password: short'],
  ['token uppercase key', 'TOKEN = VALUE12345678'],
  ['secret with spaces around equals', "secret = 'super-secret-value-1'"],
  ['anthropic key', 'using sk-ant-api03-AbCdEfGhIjKlMnOpQrStUvWxYz1234 for auth'],
  ['anthropic key too short', 'sk-ant-short1 is not a real key'],
  ['openai key', 'OPENAI=sk-AbCdEfGhIjKlMnOpQrStUvWxYz0123456789AbCdEfGh done'],
  ['bearer token', 'Authorization: Bearer eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.payload'],
  ['bearer lowercase', 'authorization: bearer abcdefghijklmnopqrstuvwxyz123456'],
  ['basic auth', 'Authorization: Basic dXNlcm5hbWU6cGFzc3dvcmQxMjM0NTY='],
  ['multiple secrets in one string', 'api_key=firstsecret123 then Bearer abcdefghijklmnopqrstu and password: anothersecret99'],
  ['secret then truncation', 'token=verylongsecretvalue1234 ' + 'x'.repeat(10100)],
  ['exactly at limit', 'y'.repeat(10000)],
  ['one over limit', 'z'.repeat(10001)],
  ['well over limit', 'a'.repeat(12345)],
  ['unicode content with secret', 'naïve café ☕ password: motdepasse123 fin'],
  ['multiline with secret', 'line one\napi-key: multiline-secret-value\nline three'],
  ['equals in surrounding text', 'x=1 y=2 comparison a==b nothing secret here'],
];

const TOOL_CASES = [
  ['websearch skipped', 'WebSearch', 'any result at all'],
  ['null result', 'Bash', null],
  ['plain string result', 'Bash', 'command output here'],
  ['string with secret', 'Bash', 'export TOKEN=shhhhhhhh123456'],
  ['object result', 'Read', { content: 'file text', lineCount: 42 }],
  ['array result', 'Bash', ['one', 'two', 3]],
  ['number result', 'Bash', 12345],
  ['boolean result', 'Bash', true],
  ['grep noisy truncation', 'Grep', 'm'.repeat(2500)],
  ['glob noisy truncation', 'Glob', 'p'.repeat(1999)],
  ['regular tool long result', 'Read', 'r'.repeat(10500)],
];

const PATH_CASES = [
  'src/index.ts',
  'node_modules/lodash/index.js',
  'project/.git/config',
  'config/.env',
  'certs/server.pem',
  'certs/private.key',
  'keys.txt',
  'aws/credentials',
  'AWS/Credentials.json',
  'app/secrets/vault.yaml',
  'MY-SECRETS.md',
  'docs/secrecy-policy.md',
  'envfile.txt',
  '.environment',
];

const fixtures = {
  '//': 'Generated by generate-fixtures.mjs — do not edit by hand.',
  content: CONTENT_CASES.map(([name, input]) => ({
    name,
    input,
    containsSecrets: hookFilter.containsSecrets(input),
    masked: hookFilter.maskSecrets(input),
    filtered: hookFilter.filterContent(input),
  })),
  tools: TOOL_CASES.map(([name, tool, result]) => ({
    name,
    tool,
    result,
    output: hookFilter.filterToolResult(tool, result),
  })),
  paths: PATH_CASES.map((path) => ({
    path,
    excluded: adapterFilter.isExcludedPath(path),
  })),
};

writeFileSync(join(here, 'fixtures.json'), JSON.stringify(fixtures, null, 2) + '\n');
console.log(
  `wrote ${fixtures.content.length} content, ${fixtures.tools.length} tool, ` +
    `${fixtures.paths.length} path fixtures`,
);
